-- {"operators": "INNER_JOIN,AGGREGATE,HAVING,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH heavy_orders AS (SELECT OL_W_ID, OL_D_ID, OL_O_ID, SUM(OL_AMOUNT) AS total FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_D_ID, OL_O_ID HAVING SUM(OL_AMOUNT) > 30) SELECT c.C_W_ID, c.C_ID, c.C_LAST, COUNT(*) AS heavy_orders_count FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN heavy_orders ho ON o.O_W_ID = ho.OL_W_ID AND o.O_D_ID = ho.OL_D_ID AND o.O_ID = ho.OL_O_ID GROUP BY c.C_W_ID, c.C_ID, c.C_LAST;
